  Datacheck() {
    console.log("valueDate", this.valueDate)
    if (this.valueDate != "Today") {
      this.processDataService();
    }
    else {
      if (this.responseDto.totalNoOfRecords == 0) {
        Swal.fire('total no. of record is 0', 'Unable to process.');
        return;
      }
      if (!this.remarks) {
        Swal.fire('Remark is mandatory for process.');
        return;
      }
      this.flag = true;

      // this.responseforfileupload.excelData .forEach(element => {
      //   element.inputBy=this.user_id;
      // });
      this.api.processDataService(this.responseforfileupload, this.user_id, this.remarks).subscribe(resp => {

        this.processDataStatus = resp;

        console.log('this.processDataStatus');
        if (this.processDataStatus) {
          // Swal.fire('Data processed Successfully.', 'you can view data in Process Excel Screen.');
          // Swal.fire("Data uploaded successfully.")
          Swal.fire(
            {
              title: "Data processed successfully",

              text: "For the Batch " + this.responseDto.batchNo
            }
          )
          this.isShow = true;

        } else {
          Swal.fire('Unable to process.');
        }
      });
    }
  }
  processDataService() {
    // console.log(this.responseforfileupload);
    // value date popup
    Swal.fire({
      text: 'Value Date is ' + this.responseDto.valueDate + ' in few or all uploading records. Would you like to proceed?',
      showCancelButton: true,
      confirmButtonColor: '#3085d6',
      cancelButtonColor: '#d33',
      confirmButtonText: 'PROCEED.'
    }).then((result) => {
      console.log(result.value);
      if (result.value) {
        console.log('user choose to proceed.');

        if (this.responseDto.totalNoOfRecords == 0) {
          Swal.fire('total no. of record is 0', 'Unable to process.');
          return;
        }
        if (!this.remarks) {
          Swal.fire('Remark is mandatory for process.');
          return;
        }
        this.flag = true;

        // this.responseforfileupload.excelData .forEach(element => {
        //   element.inputBy=this.user_id;
        // });
        this.api.processDataService(this.responseforfileupload, this.user_id, this.remarks).subscribe(resp => {

          this.processDataStatus = resp;

          console.log('this.processDataStatus');
          if (this.processDataStatus) {
            // Swal.fire('Data processed Successfully.', 'you can view data in Process Excel Screen.');
            // Swal.fire("Data uploaded successfully.")
            Swal.fire(
              {
                title: "Data processed successfully",

                text: "For the Batch " + this.responseDto.batchNo
              }
            )
            this.isShow = true;

          } else {
            Swal.fire('Unable to process.');
          }
        });

      } else {
        return;
      }

    })

  }
